try {
  const wd = sim.worldData
  if (!wd.__init) {
    wd.__init = 1
    wd.ch = { x: 0, y: -0.35, dir: 0, pulse: 0, cd: 0, target: -1 }
    wd.cr = []
    for (let i = 0; i < 8; i++) wd.cr.push({ x: Math.random()*1.7-0.85, y: Math.random()*1.0-0.55, vx:(Math.random()-0.5)*0.003, vy:(Math.random()-0.5)*0.002, fr:0 })
    wd.singlePlayer = true
    wd.__play_music = { score: { bpm: 64, loop: true, gain: 0.42, swing: 0.05, tracks: [
      { inst:'triangle', gain:0.4, cutoff:500, a:0.05, d:2.6, notes:'C2 . . . . . . . G2 . . . . . . .' },
      { inst:'sawtooth', gain:0.12, cutoff:700, a:1.0, d:3.0, notes:'C4+E4+G4 . . . . . . . A3+C4+E4 . . . . . . .' },
      { inst:'sine', gain:0.1, cutoff:2200, a:0.05, d:1.5, notes:'. . . . G4 . . . . . E4 . . . C5 .' },
    ] } }
  }
  const C = wd.ch, CR = wd.cr
  for (const c of CR) {
    if (c.fr < 0.5) {
      c.vx += (Math.random()-0.5)*0.0006; c.vy += (Math.random()-0.5)*0.0004
      c.vx = Math.max(-0.006, Math.min(0.006, c.vx)); c.vy = Math.max(-0.004, Math.min(0.004, c.vy))
      c.x += c.vx; c.y += c.vy
      if (c.x < -0.92 || c.x > 0.92) c.vx *= -1
      if (c.y < -0.85 || c.y > 0.72) c.vy *= -1
      c.x = Math.max(-0.92, Math.min(0.92, c.x)); c.y = Math.max(-0.85, Math.min(0.72, c.y))
    }
  }
  if (C.cd > 0) C.cd -= 1
  if (C.target < 0 && C.cd <= 0) {
    const un = CR.map((c,i)=>({c,i})).filter(o=>o.c.fr<0.5)
    const fz = CR.map((c,i)=>({c,i})).filter(o=>o.c.fr>=0.5)
    let pool = un.length ? un : fz
    if (fz.length && un.length && Math.random() < 0.22) pool = fz
    if (pool.length) { pool.sort((a,b)=>((a.c.x-C.x)**2+(a.c.y-C.y)**2)-((b.c.x-C.x)**2+(b.c.y-C.y)**2)); C.target = pool[0].i }
  }
  if (C.target >= 0) {
    const tc = CR[C.target]
    const dx = tc.x - C.x, dy = (tc.y + 0.02) - C.y, dist = Math.hypot(dx, dy)
    if (dx !== 0) C.dir = dx
    if (dist > 0.05) { C.x += dx/dist*0.008; C.y += dy/dist*0.008 }
    else {
      tc.fr = tc.fr >= 0.5 ? 0 : 1
      C.pulse = 1
      wd.__play_sound = tc.fr >= 0.5
        ? [{frequency:1250,duration:0.14,volume:0.3,type:'triangle'},{frequency:1900,duration:0.28,volume:0.2,type:'sine'}]
        : [{frequency:380,duration:0.3,volume:0.28,type:'sine'},{frequency:280,duration:0.45,volume:0.2,type:'triangle'}]
      C.target = -1; C.cd = 45
    }
  }
  if (C.pulse > 0.01) C.pulse = Math.max(0, C.pulse - 0.035)
  const frozenFrac = CR.filter(c=>c.fr>=0.5).length / CR.length
  wd.music_mod = { brightness: 1 - frozenFrac * 0.6, gain: 1 }
  const u = new Array(40).fill(-9)
  u[0]=C.x; u[1]=C.y; u[2]=C.dir||0; u[3]=C.pulse
  for (let i=0;i<CR.length && i<8;i++){ const b=4+i*3; u[b]=CR[i].x; u[b+1]=CR[i].y; u[b+2]=CR[i].fr }
  u[30]=frozenFrac
  wd.gpuUniforms = u
} catch(e){}

