fn visual_still(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let p = uv;
  let horizon = -0.12;
  var col: vec3f;
  if (p.y > horizon) {
    let s = (p.y - horizon) / (1.0 - horizon);
    col = mix(vec3f(0.34, 0.26, 0.40), vec3f(0.05, 0.06, 0.16), pow(s, 0.65));
    let sp = p * 9.0; let h = hash21(floor(sp));
    if (h > 0.984 && p.y > 0.05) {
      col += vec3f(0.8, 0.85, 1.0) * smoothstep(0.09, 0.0, length(fract(sp) - 0.5)) * (0.4 + 0.5 * sin(t * 2.0 + h * 40.0));
    }
  } else {
    let d = horizon - p.y;
    let fog = exp(-d * 2.6);
    var g = mix(vec3f(0.04, 0.055, 0.08), vec3f(0.09, 0.12, 0.11), fog);
    g *= 0.82 + 0.18 * fbm3(vec2f(p.x * 4.0, d * 7.0));
    col = g;
  }
  col += vec3f(0.55, 0.36, 0.26) * exp(-abs(p.y - horizon) * 6.0) * 0.45;

  let frozenFrac = uni(30);

  // creatures
  for (var i = 0; i < 8; i = i + 1) {
    let b = 4 + i * 3;
    let cx = uni(b); let cy = uni(b + 1); let fr = clamp(uni(b + 2), 0.0, 1.0);
    if (cx < -5.0) { continue; }
    let cp = p - vec2f(cx, cy);
    let d = length(cp);
    let warm = vec3f(1.3, 0.95, 0.45) * (0.6 + 0.4 * sin(t * 3.0 + f32(i) * 1.7));
    let cold = vec3f(0.55, 0.85, 1.35);
    let cc = mix(warm, cold, fr);
    col += cc * exp(-d * d * 700.0) * (1.0 + fr * 0.6);
    col += cc * exp(-d * 34.0) * 0.13;
    if (fr > 0.25) {
      let ang = atan2(cp.y, cp.x);
      let fac = 0.5 + 0.5 * sin(ang * 6.0 + 1.0);
      col += cold * fac * exp(-d * d * 260.0) * fr * 0.6;
    }
  }

  // the figure — a warm lantern-bearer with a soft ground shadow
  let ch = vec2f(uni(0), uni(1));
  let cp = p - ch;
  let sh = length((p - vec2f(ch.x, ch.y - 0.05)) * vec2f(1.0, 2.6));
  col = col * (1.0 - 0.4 * smoothstep(0.09, 0.0, sh));
  let bd = length(cp * vec2f(1.0, 0.78));
  col += vec3f(1.5, 1.15, 0.7) * exp(-bd * bd * 420.0);
  col += vec3f(1.0, 0.8, 0.5) * exp(-bd * 20.0) * 0.16;

  // freeze pulse from the figure
  let pulse = uni(3);
  if (pulse > 0.01) {
    let r = (1.0 - pulse) * 0.5;
    let ring = abs(length(cp) - r);
    col += vec3f(0.6, 0.9, 1.35) * smoothstep(0.03, 0.0, ring) * pulse * 0.9;
  }

  col = mix(col, col * vec3f(0.82, 0.95, 1.2), frozenFrac * 0.45);
  col = col * (1.0 - 0.32 * pow(length(uv), 2.2));
  if (col.x != col.x) { col = vec3f(0.02); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(30.0)), 1.0);
}
